module johnson_counter_3bit (clk, rst, q);
   input clk, rst;
   output [2:0] q;

   reg [2:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst) 
    begin
        q <= 3'b000;
    end 
    else 
    begin
        q <= {q[1:0], ~q[2]};
    end
end

endmodule
